#include <stdio.h>
#include <string.h>

int main(void) {
    char text[42];
    if (fgets(text, sizeof text, stdin) == NULL) return 1;
    size_t length = strcspn(text, "\n");
    if (text[length] == '\n') text[length] = '\0';
    for (size_t i = 0; i < length; ++i) if (text[i] < 'a' || text[i] > 'z') { puts("invalid"); return 0; }
    for (size_t i = length; i > 0; --i) putchar(text[i - 1]);
    putchar('\n');
    return 0;
}
